class Solution:
    def findCrossingTime(self, n, k, time):
        state = ['LEFT_IDLE'] * k
        timer = [0] * k
        to_pick = n
        delivered = 0
        t = 0
        bridge_worker = None
        answer = 0

        def eff_key(i):
            r, p, l, u = time[i]
            return (r + l, i)

        while delivered < n:
            if bridge_worker is None:
                ready = [i for i in range(k) if state[i] == 'READY_L']
                if ready:
                    i = max(ready, key=eff_key)
                    state[i] = 'CROSS_L'
                    timer[i] = time[i][2]
                    bridge_worker = i
                elif to_pick > 0:
                    idle = [i for i in range(k) if state[i] == 'LEFT_IDLE']
                    if idle:
                        i = max(idle, key=eff_key)
                        state[i] = 'CROSS_R'
                        timer[i] = time[i][0]
                        bridge_worker = i
                        to_pick -= 1

            t += 1
            finishing = []
            if bridge_worker is not None:
                timer[bridge_worker] -= 1
                if timer[bridge_worker] == 0:
                    finishing.append(bridge_worker)
            for i in range(k):
                if state[i] in ('PICK', 'PUT'):
                    timer[i] -= 1
                    if timer[i] == 0:
                        finishing.append(i)

            for i in finishing:
                if state[i] == 'CROSS_R':
                    state[i] = 'PICK'
                    timer[i] = time[i][1]
                    bridge_worker = None
                elif state[i] == 'CROSS_L':
                    delivered += 1
                    answer = t
                    if delivered < n:
                        state[i] = 'PUT'
                        timer[i] = time[i][3]
                    else:
                        state[i] = 'DONE'
                    bridge_worker = None
                elif state[i] == 'PICK':
                    state[i] = 'READY_L'
                elif state[i] == 'PUT':
                    state[i] = 'LEFT_IDLE'

            if delivered >= n:
                break

        return answer

