class Solution:
    def findCrossingTime(self, n, k, time):
        import heapq

        def key(i):
            r, p, l, u = time[i]
            return (-(r + l), -i)

        wait_right = [key(i) for i in range(k)]
        heapq.heapify(wait_right)
        wait_left = []
        picking = []
        putting = []

        cur = 0
        to_pick = n
        delivered = 0
        answer = 0

        while delivered < n:
            while picking and picking[0][0] <= cur:
                _, i = heapq.heappop(picking)
                heapq.heappush(wait_left, key(i))
            while putting and putting[0][0] <= cur:
                _, i = heapq.heappop(putting)
                if to_pick > 0:
                    heapq.heappush(wait_right, key(i))

            if wait_left:
                _, ni = heapq.heappop(wait_left)
                i = -ni
                cur += time[i][2]
                delivered += 1
                answer = cur
                if delivered < n:
                    heapq.heappush(putting, (cur + time[i][3], i))
            elif wait_right and to_pick > 0:
                _, ni = heapq.heappop(wait_right)
                i = -ni
                cur += time[i][0]
                to_pick -= 1
                heapq.heappush(picking, (cur + time[i][1], i))
            else:
                nxt = []
                if picking:
                    nxt.append(picking[0][0])
                if putting:
                    nxt.append(putting[0][0])
                cur = min(nxt)

        return answer

