var findCrossingTime = function(n, k, time) {
    class MinHeap {
        constructor(cmp) {
            this.data = [];
            this.cmp = cmp;
        }
        get size() { return this.data.length; }
        peek() { return this.data[0]; }
        push(item) {
            const a = this.data;
            a.push(item);
            let i = a.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (this.cmp(a[i], a[p]) < 0) {
                    const tmp = a[i]; a[i] = a[p]; a[p] = tmp;
                    i = p;
                } else break;
            }
        }
        pop() {
            const a = this.data;
            const top = a[0];
            const last = a.pop();
            if (a.length > 0) {
                a[0] = last;
                let i = 0;
                const len = a.length;
                while (true) {
                    const l = 2 * i + 1, r = 2 * i + 2;
                    let smallest = i;
                    if (l < len && this.cmp(a[l], a[smallest]) < 0) smallest = l;
                    if (r < len && this.cmp(a[r], a[smallest]) < 0) smallest = r;
                    if (smallest === i) break;
                    const tmp = a[i]; a[i] = a[smallest]; a[smallest] = tmp;
                    i = smallest;
                }
            }
            return top;
        }
    }

    const cmpKey = (x, y) => (x[0] !== y[0] ? x[0] - y[0] : x[1] - y[1]);
    const cmpTime = (x, y) => x[0] - y[0];
    const key = (i) => {
        const r = time[i][0], l = time[i][2];
        return [-(r + l), -i];
    };

    const waitRight = new MinHeap(cmpKey);
    for (let i = 0; i < k; i++) waitRight.push(key(i));
    const waitLeft = new MinHeap(cmpKey);
    const picking = new MinHeap(cmpTime);
    const putting = new MinHeap(cmpTime);

    let cur = 0;
    let toPick = n;
    let delivered = 0;
    let answer = 0;

    while (delivered < n) {
        while (picking.size > 0 && picking.peek()[0] <= cur) {
            const item = picking.pop();
            waitLeft.push(key(item[1]));
        }
        while (putting.size > 0 && putting.peek()[0] <= cur) {
            const item = putting.pop();
            if (toPick > 0) waitRight.push(key(item[1]));
        }

        if (waitLeft.size > 0) {
            const top = waitLeft.pop();
            const i = -top[1];
            cur += time[i][2];
            delivered++;
            answer = cur;
            if (delivered < n) putting.push([cur + time[i][3], i]);
        } else if (waitRight.size > 0 && toPick > 0) {
            const top = waitRight.pop();
            const i = -top[1];
            cur += time[i][0];
            toPick--;
            picking.push([cur + time[i][1], i]);
        } else {
            let nxt = Infinity;
            if (picking.size > 0) nxt = Math.min(nxt, picking.peek()[0]);
            if (putting.size > 0) nxt = Math.min(nxt, putting.peek()[0]);
            cur = nxt;
        }
    }

    return answer;
};
